values.content:
你是一個專業的內容架構師與大學學科校正專家。收到一份連續的對話逐字稿陣列。

【絕對規則】
1. 嚴格一對一校正：輸入有幾個句子，`corrected_segments` 就必須有幾個物件。絕對禁止刪除任何一個 id，否則系統會崩潰。
2. 只回傳 `id` 與校正後的 `text`，不需要回傳時間座標。
3. 專有名詞校正：這是一堂 Computer Networking 課程，請將錯誤的拼音修正為精確的學術名詞（如：Data Grim -> Datagram, Rotters -> Routers, Second -> Segment, Death Nation -> Destination, DataPlan -> Data Plane, PortRouting -> Routing Protocol 等）。

【輸出格式】
必須是合法 JSON：
{
  "reasoning": "簡述你修正了哪些關鍵名詞，以及章節的切分邏輯。",
  "chapters": [
    {
      "chapter_title": "章節標題",
      "summary_bullets": ["摘要1", "摘要2", "摘要3", "摘要4", "摘要5"],
      "start_id": 該章節第一句話的id,
      "end_id": 該章節最後一句話的id
    }
  ],
  "corrected_segments": [
    {"id": 原id, "text": "校正錯字後的完整句子"}
  ]
}

parameters.jsCode:
const allChapters = $input.all().map(item => item.json);

if (allChapters.length === 0) {
    throw new Error("沒有接收到任何資料。");
}

allChapters.sort((a, b) => a.start_time - b.start_time);

const finalPayload = {
    project_generated_at: new Date().toISOString(),
    total_chapters: allChapters.length,
    chapters: allChapters.map((chap, i) => ({
        chapter_id: i + 1,
        title: chap.chapter_title,
        start_time: chap.start_time,
        end_time: chap.end_time,
        summary: chap.summary_bullets,
        transcript: chap.corrected_segments
    }))
};

return [{ json: { final_output: finalPayload } }];

const segments = $input.first().json.segments || [];
if (segments.length === 0) throw new Error("ASR 辨識結果為空");

const mappedSegs = segments.map((s, i) => ({ id: i, start: s.start, end: s.end, text: s.text }));

const SOFT_LIMIT = 240; 
const HARD_LIMIT = 360; 

let batches = [];
let currentBatch = [];
let batchStartTime = 0;

for (let seg of mappedSegs) {
    if (currentBatch.length === 0) batchStartTime = seg.start;
    currentBatch.push(seg);

    const duration = seg.end - batchStartTime;

    const textTrimmed = seg.text.trim();
    const hasPunctuation = /[。！？.!?]$/.test(textTrimmed);

    if ((duration >= SOFT_LIMIT && hasPunctuation) || duration >= HARD_LIMIT) {
        batches.push({ raw_segments: currentBatch });
        currentBatch = [];
    }
}

if (currentBatch.length > 0) {
    batches.push({ raw_segments: currentBatch });
}

return batches.map((b, i) => ({
    json: { batch_id: i + 1, raw_segments: b.raw_segments }
}));

const results = [];
const allOriginals = $("2. 逐字稿動態分塊").all();

for (let i = 0; i < $input.all().length; i++) {
    const currentInput = $input.all()[i];

    let aiData = {};
    if (currentInput.json.output && currentInput.json.output[0]?.content) {
        aiData = currentInput.json.output[0].content[0]?.text || {};
    } else {
        const content = currentInput.json.message?.content || currentInput.json.text || "{}";
        try {
            aiData = typeof content === 'string' ? JSON.parse(content) : content;
        } catch(e) {}
    }

    if (typeof aiData === 'string') {
        try { aiData = JSON.parse(aiData); } catch(e) {}
    }

    const originalSegments = allOriginals[i]?.json?.raw_segments || [];
    const llmTextMap = {};
    (aiData.corrected_segments || []).forEach(seg => {
        llmTextMap[seg.id] = seg.text;
    });

    const bulletproofSegments = originalSegments.map(orig => ({
        original_id: orig.id, // 保留錨點
        id: originalSegments.indexOf(orig) + 1, 
        start: orig.start,
        end: orig.end,
        text: llmTextMap[orig.id] || orig.text 
    }));

    const chapters = aiData.chapters || [];

    chapters.forEach((chap) => {
        const chapSegs = bulletproofSegments.filter(s => 
            (s.original_id >= chap.start_id) && 
            (s.original_id <= chap.end_id)
        );

        chapSegs.forEach(s => delete s.original_id);

        const start_time = chapSegs.length > 0 ? chapSegs[0].start : 0;
        const end_time = chapSegs.length > 0 ? chapSegs[chapSegs.length - 1].end : 0;

        results.push({
            json: {
                chapter_title: chap.chapter_title,
                start_time: start_time,
                end_time: end_time,
                summary_bullets: chap.summary_bullets,
                corrected_segments: chapSegs
            }
        });
    });
}

if (results.length === 0) {
    throw new Error("提取失敗：檢查 LLM 節點是否確實吐出 JSON 格式，或檢查上游節點。");
}

return results;
